import * as THREE from 'three';

const SKILLS = [
  'Python', 'Rust', 'C', 'React', 'Next.js', 'HTML5',
  'Node.js', 'MongoDB', 'MySQL', 'AWS', 'Firebase', 'Oracle',
];

export class SkillsOrbit {
  constructor(canvas) {
    this.canvas = canvas;
    this.labels = SKILLS;

    this.scene = new THREE.Scene();
    this.camera = new THREE.PerspectiveCamera(50, 1, 0.1, 100);
    this.camera.position.z = 8;

    this.renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true });
    this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));

    const coreGeo = new THREE.SphereGeometry(0.55, 32, 32);
    const coreMat = new THREE.MeshBasicMaterial({
      color: 0x8b5cf6,
      transparent: true,
      opacity: 0.9,
    });
    this.core = new THREE.Mesh(coreGeo, coreMat);
    this.scene.add(this.core);

    const glowGeo = new THREE.SphereGeometry(0.75, 32, 32);
    const glowMat = new THREE.MeshBasicMaterial({
      color: 0x00d4ff,
      transparent: true,
      opacity: 0.12,
      wireframe: true,
    });
    this.glow = new THREE.Mesh(glowGeo, glowMat);
    this.scene.add(this.glow);

    this.nodes = [];
    const orbitRadius = 3.2;
    this.labels.forEach((label, i) => {
      const angle = (i / this.labels.length) * Math.PI * 2;
      const y = Math.sin(i * 1.7) * 1.2;
      const group = new THREE.Group();

      const dotGeo = new THREE.SphereGeometry(0.08, 12, 12);
      const dotMat = new THREE.MeshBasicMaterial({
        color: i % 2 === 0 ? 0x00d4ff : 0x8b5cf6,
      });
      const dot = new THREE.Mesh(dotGeo, dotMat);
      group.add(dot);

      const sprite = this._createLabelSprite(label);
      sprite.position.set(0, 0.25, 0);
      sprite.scale.set(1.8, 0.45, 1);
      group.add(sprite);

      group.userData = {
        angle,
        radius: orbitRadius + (i % 3) * 0.3,
        y,
        speed: 0.3 + (i % 5) * 0.05,
        label,
      };

      this.scene.add(group);
      this.nodes.push(group);
    });

    this._buildConnections();
    this.clock = new THREE.Clock();
    this._resize();
    window.addEventListener('resize', () => this._resize());
  }

  _createLabelSprite(text) {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    canvas.width = 256;
    canvas.height = 64;
    ctx.fillStyle = 'rgba(10, 10, 15, 0.6)';
    ctx.fillRect(0, 0, 256, 64);
    ctx.font = 'bold 28px Orbitron, sans-serif';
    ctx.fillStyle = '#00d4ff';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(text, 128, 32);

    const texture = new THREE.CanvasTexture(canvas);
    const material = new THREE.SpriteMaterial({ map: texture, transparent: true });
    return new THREE.Sprite(material);
  }

  _buildConnections() {
    const positions = [];
    this.nodes.forEach((node, i) => {
      const next = this.nodes[(i + 1) % this.nodes.length];
      positions.push(0, 0, 0, 0, 0, 0);
      node.userData.lineIndex = positions.length / 3 - 2;
      next.userData.prevLineIndex = positions.length / 3 - 2;
    });

    const geo = new THREE.BufferGeometry();
    geo.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
    const mat = new THREE.LineBasicMaterial({
      color: 0x00d4ff,
      transparent: true,
      opacity: 0.15,
    });
    this.connectionLines = new THREE.LineSegments(geo, mat);
    this.scene.add(this.connectionLines);
    this.linePositions = geo.attributes.position.array;
  }

  _resize() {
    const parent = this.canvas.parentElement;
    const w = parent.clientWidth;
    const h = parent.clientHeight;
    this.camera.aspect = w / h;
    this.camera.updateProjectionMatrix();
    this.renderer.setSize(w, h);
  }

  render() {
    const t = this.clock.getElapsedTime();
    this.core.rotation.y = t * 0.2;
    this.glow.rotation.x = t * 0.15;
    this.glow.rotation.z = t * 0.1;

    const linePos = this.linePositions;
    let li = 0;

    this.nodes.forEach((group, i) => {
      const { angle, radius, y, speed } = group.userData;
      const a = angle + t * speed;
      const x = Math.cos(a) * radius;
      const z = Math.sin(a) * radius;
      group.position.set(x, y + Math.sin(t + i) * 0.15, z);
      group.lookAt(0, y, 0);

      if (li < linePos.length - 5) {
        linePos[li++] = x;
        linePos[li++] = y;
        linePos[li++] = z;
        linePos[li++] = 0;
        linePos[li++] = 0;
        linePos[li++] = 0;
      }
    });

    if (this.connectionLines) {
      this.connectionLines.geometry.attributes.position.needsUpdate = true;
    }

    this.renderer.render(this.scene, this.camera);
  }

  dispose() {
    this.renderer.dispose();
  }
}

import gsap from 'gsap';

export function initCursor() {
  const cursor = document.getElementById('cursor');
  if (!cursor || window.matchMedia('(pointer: coarse)').matches) return null;

  const dot = cursor.querySelector('.cursor__dot');
  const ring = cursor.querySelector('.cursor__ring');
  const trails = [];

  for (let i = 0; i < 6; i++) {
    const t = document.createElement('motion-preference');
    t.className = 'cursor__trail';
    cursor.appendChild(t);
    trails.push(t);
  }

  const pos = { x: window.innerWidth / 2, y: window.innerHeight / 2 };
  const target = { ...pos };

  document.addEventListener('mousemove', (e) => {
    target.x = e.clientX;
    target.y = e.clientY;
  });

  const hoverables = document.querySelectorAll(
    'a, button, [data-cursor="hover"], .project-card, .contact-icon, .btn'
  );
  hoverables.forEach((el) => {
    el.addEventListener('mouseenter', () => cursor.classList.add('is-hover'));
    el.addEventListener('mouseleave', () => cursor.classList.remove('is-hover'));
  });

  document.querySelectorAll('.magnetic').forEach((el) => {
    el.addEventListener('mousemove', (e) => {
      const rect = el.getBoundingClientRect();
      const x = e.clientX - rect.left - rect.width / 2;
      const y = e.clientY - rect.top - rect.height / 2;
      gsap.to(el, { x: x * 0.2, y: y * 0.2, duration: 0.4, ease: 'power2.out' });
    });
    el.addEventListener('mouseleave', () => {
      gsap.to(el, { x: 0, y: 0, duration: 0.6, ease: 'elastic.out(1, 0.4)' });
    });
  });

  function tick() {
    pos.x += (target.x - pos.x) * 0.18;
    pos.y += (target.y - pos.y) * 0.18;

    gsap.set(dot, { x: pos.x, y: pos.y });
    gsap.set(ring, { x: pos.x, y: pos.y });

    trails.forEach((trail, i) => {
      const delay = (i + 1) * 0.04;
      const tx = target.x + (pos.x - target.x) * delay * 8;
      const ty = target.y + (pos.y - target.y) * delay * 8;
      gsap.set(trail, {
        x: tx,
        y: ty,
        opacity: 0.35 - i * 0.05,
        scale: 1 - i * 0.1,
      });
    });

    requestAnimationFrame(tick);
  }

  tick();
  return cursor;
}

import gsap from 'gsap';

export function runPreloader(onComplete) {
  const preloader = document.getElementById('preloader');
  const progress = document.getElementById('preloader-progress');
  const letters = document.querySelectorAll('.preloader__letter');

  if (!preloader) {
    onComplete?.();
    return;
  }

  document.body.style.overflow = 'hidden';

  const tl = gsap.timeline({
    onComplete: () => {
      preloader.classList.add('is-done');
      document.body.classList.add('is-loaded');
      document.body.style.overflow = '';
      onComplete?.();
    },
  });

  tl.to(letters, {
    opacity: 1,
    y: 0,
    duration: 0.6,
    stagger: 0.12,
    ease: 'power3.out',
  })
    .to(
      progress,
      {
        width: '100%',
        duration: 1.4,
        ease: 'power2.inOut',
      },
      '-=0.2'
    )
    .to(preloader, {
      opacity: 0,
      duration: 0.6,
      ease: 'power2.inOut',
    })
    .set(preloader, { pointerEvents: 'none' });
}

export function initTiltCards() {
  const cards = document.querySelectorAll('[data-tilt]');
  if (window.matchMedia('(pointer: coarse)').matches) return;

  cards.forEach((card) => {
    card.addEventListener('mousemove', (e) => {
      const rect = card.getBoundingClientRect();
      const x = (e.clientX - rect.left) / rect.width;
      const y = (e.clientY - rect.top) / rect.height;
      const rotateX = (y - 0.5) * -12;
      const rotateY = (x - 0.5) * 12;

      card.style.setProperty('--mx', `${x * 100}%`);
      card.style.setProperty('--my', `${y * 100}%`);
      card.style.transform = `perspective(800px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) scale3d(1.02, 1.02, 1.02)`;
    });

    card.addEventListener('mouseleave', () => {
      card.style.transform = 'perspective(800px) rotateX(0) rotateY(0) scale3d(1, 1, 1)';
    });
  });
}

export function initFooterParticles(canvas) {
  if (!canvas) return () => {};

  const ctx = canvas.getContext('2d');
  const particles = [];
  const count = 40;

  function resize() {
    const parent = canvas.parentElement;
    canvas.width = parent.offsetWidth;
    canvas.height = parent.offsetHeight;
  }

  for (let i = 0; i < count; i++) {
    particles.push({
      x: Math.random() * 800,
      y: Math.random() * 120,
      vx: (Math.random() - 0.5) * 0.3,
      vy: (Math.random() - 0.5) * 0.2,
      r: 1 + Math.random() * 2,
      a: 0.2 + Math.random() * 0.5,
    });
  }

  resize();
  window.addEventListener('resize', resize);

  let raf;
  function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    particles.forEach((p) => {
      p.x += p.vx;
      p.y += p.vy;
      if (p.x < 0 || p.x > canvas.width) p.vx *= -1;
      if (p.y < 0 || p.y > canvas.height) p.vy *= -1;

      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(0, 212, 255, ${p.a})`;
      ctx.fill();
    });

    for (let i = 0; i < particles.length; i++) {
      for (let j = i + 1; j < particles.length; j++) {
        const dx = particles[i].x - particles[j].x;
        const dy = particles[i].y - particles[j].y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 80) {
          ctx.strokeStyle = `rgba(139, 92, 246, ${0.15 * (1 - dist / 80)})`;
          ctx.beginPath();
          ctx.moveTo(particles[i].x, particles[i].y);
          ctx.lineTo(particles[j].x, particles[j].y);
          ctx.stroke();
        }
      }
    }

    raf = requestAnimationFrame(draw);
  }

  draw();

  return () => {
    cancelAnimationFrame(raf);
    window.removeEventListener('resize', resize);
  };
}

