      onEnter: () => {
        el.classList.add('is-glitching');
        setTimeout(() => el.classList.remove('is-glitching'), 400);
      },
    });
  });

  ScrollTrigger.create({
    trigger: document.body,
    start: 'top top',
    end: 'bottom bottom',
    onUpdate: (self) => onScrollProgress?.(self.progress),
  });

  const cameraKeyframes = [
    { section: 0, z: 12, y: 0, x: 0 },
    { section: 1, z: 8, y: 1, x: -1.5 },
    { section: 2, z: 7, y: 0.5, x: 1 },
    { section: 3, z: 9, y: -0.5, x: 0 },
    { section: 4, z: 10, y: 0, x: 0 },
  ];

  cameraKeyframes.forEach((kf, i) => {
    const trigger = document.querySelector(`[data-section="${kf.section}"]`);
    if (!trigger) return;
    ScrollTrigger.create({
      trigger,
      start: 'top center',
      end: 'bottom center',
      onEnter: () => onScrollProgress?.(i / (cameraKeyframes.length - 1)),
      onEnterBack: () => onScrollProgress?.(i / (cameraKeyframes.length - 1)),
    });
  });
}

